
        select aod.as_of_date, t.*
        from as_of_dates as aod
        cross join lateral (

        with

        
        -- Aggregate for patients
        visits_aggs_for_patients as (
        select
        visits_transform.patient_id,
        count( visit_id ) as "COUNT(visits.visit_id)" ,count( visit_id )  filter (where  daterange((aod.as_of_date - interval 'P1D')::date, aod.as_of_date::date, '[]')  @>  visited_at)  as "COUNT(visits.visit_id|interval=P1D)" ,count( visited_at ) as "COUNT(visits.visited_at)" ,count( visited_at )  filter (where  daterange((aod.as_of_date - interval 'P1D')::date, aod.as_of_date::date, '[]')  @>  visited_at)  as "COUNT(visits.visited_at|interval=P1D)" ,avg( duration_minutes ) as "MEAN(visits.duration_minutes)" ,avg( duration_minutes )  filter (where  daterange((aod.as_of_date - interval 'P1D')::date, aod.as_of_date::date, '[]')  @>  visited_at)  as "MEAN(visits.duration_minutes|interval=P1D)" ,stddev( duration_minutes ) as "STDDEV(visits.duration_minutes)" ,stddev( duration_minutes )  filter (where  daterange((aod.as_of_date - interval 'P1D')::date, aod.as_of_date::date, '[]')  @>  visited_at)  as "STDDEV(visits.duration_minutes|interval=P1D)" ,sum( duration_minutes ) as "SUM(visits.duration_minutes)" ,sum( duration_minutes )  filter (where  daterange((aod.as_of_date - interval 'P1D')::date, aod.as_of_date::date, '[]')  @>  visited_at)  as "SUM(visits.duration_minutes|interval=P1D)" 
        from visits_transform
        where aod.as_of_date >= visited_at
        group by patient_id
        )
        ,
        -- sythetize aggregations and direct features for patients
        patients_synth as (
        select
        analytics.patients.patient_id, analytics.patients.registered_at, analytics.patients.patient_id, "COUNT(visits.visit_id)", "COUNT(visits.visit_id|interval=P1D)", "COUNT(visits.visited_at)", "COUNT(visits.visited_at|interval=P1D)", "MEAN(visits.duration_minutes)", "MEAN(visits.duration_minutes|interval=P1D)", "STDDEV(visits.duration_minutes)", "STDDEV(visits.duration_minutes|interval=P1D)", "SUM(visits.duration_minutes)", "SUM(visits.duration_minutes|interval=P1D)", age, risk_score
        from analytics.patients
         left join 
         lateral (
        select
        care_plans_transform.risk_score as "risk_score"
        from care_plans_transform
        where care_plans_transform.patient_id = analytics.patients.patient_id and care_plans_transform.effective_at <= analytics.patients.registered_at and analytics.patients.registered_at - care_plans_transform.effective_at <= interval 'P14D'
        order by care_plans_transform.effective_at desc
        limit 1
    ) as care_plans_asof_for_patients on true  left join  visits_aggs_for_patients on visits_aggs_for_patients.patient_id = analytics.patients.patient_id 
        )
        ,
        -- transform patients
        patients_transform as (
        select
        patient_id, registered_at, patient_id,  abs(risk_score)  as "ABS(care_plans.risk_score)" ,  abs("COUNT(visits.visit_id)")  as "ABS(patients.COUNT(visits.visit_id))" ,  abs("COUNT(visits.visit_id|interval=P1D)")  as "ABS(patients.COUNT(visits.visit_id|interval=P1D))" ,  abs("COUNT(visits.visited_at)")  as "ABS(patients.COUNT(visits.visited_at))" ,  abs("COUNT(visits.visited_at|interval=P1D)")  as "ABS(patients.COUNT(visits.visited_at|interval=P1D))" ,  abs("MEAN(visits.duration_minutes)")  as "ABS(patients.MEAN(visits.duration_minutes))" ,  abs("MEAN(visits.duration_minutes|interval=P1D)")  as "ABS(patients.MEAN(visits.duration_minutes|interval=P1D))" ,  abs("STDDEV(visits.duration_minutes)")  as "ABS(patients.STDDEV(visits.duration_minutes))" ,  abs("STDDEV(visits.duration_minutes|interval=P1D)")  as "ABS(patients.STDDEV(visits.duration_minutes|interval=P1D))" ,  abs("SUM(visits.duration_minutes)")  as "ABS(patients.SUM(visits.duration_minutes))" ,  abs("SUM(visits.duration_minutes|interval=P1D)")  as "ABS(patients.SUM(visits.duration_minutes|interval=P1D))" ,  abs(age)  as "ABS(patients.age)" , count( visit_id ) as "COUNT(visits.visit_id)" , count( visit_id )  filter (where  daterange((aod.as_of_date - interval 'P1D')::date, aod.as_of_date::date, '[]')  @>  visited_at)  as "COUNT(visits.visit_id|interval=P1D)" , count( visited_at ) as "COUNT(visits.visited_at)" , count( visited_at )  filter (where  daterange((aod.as_of_date - interval 'P1D')::date, aod.as_of_date::date, '[]')  @>  visited_at)  as "COUNT(visits.visited_at|interval=P1D)" , sum(risk_score)  over (partition by patient_id  order by effective_at ) as "CUM_SUM(care_plans.risk_score)" , sum("COUNT(visits.visit_id)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.COUNT(visits.visit_id))" , sum("COUNT(visits.visit_id|interval=P1D)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.COUNT(visits.visit_id|interval=P1D))" , sum("COUNT(visits.visited_at)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.COUNT(visits.visited_at))" , sum("COUNT(visits.visited_at|interval=P1D)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.COUNT(visits.visited_at|interval=P1D))" , sum("MEAN(visits.duration_minutes)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.MEAN(visits.duration_minutes))" , sum("MEAN(visits.duration_minutes|interval=P1D)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.MEAN(visits.duration_minutes|interval=P1D))" , sum("STDDEV(visits.duration_minutes)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.STDDEV(visits.duration_minutes))" , sum("STDDEV(visits.duration_minutes|interval=P1D)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.STDDEV(visits.duration_minutes|interval=P1D))" , sum("SUM(visits.duration_minutes)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.SUM(visits.duration_minutes))" , sum("SUM(visits.duration_minutes|interval=P1D)")  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.SUM(visits.duration_minutes|interval=P1D))" , sum(age)  over (partition by patient_id  order by registered_at ) as "CUM_SUM(patients.age)" , sum(risk_score * exp(0.25 * (extract(epoch from effective_at) / 86400.0))) over (partition by patient_id order by effective_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from effective_at) / 86400.0))) over (partition by patient_id order by effective_at rows between 6 preceding and current row), 0) as "EMA_7(care_plans.risk_score)" , sum("COUNT(visits.visit_id)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.COUNT(visits.visit_id))" , sum("COUNT(visits.visit_id|interval=P1D)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.COUNT(visits.visit_id|interval=P1D))" , sum("COUNT(visits.visited_at)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.COUNT(visits.visited_at))" , sum("COUNT(visits.visited_at|interval=P1D)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.COUNT(visits.visited_at|interval=P1D))" , sum("MEAN(visits.duration_minutes)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.MEAN(visits.duration_minutes))" , sum("MEAN(visits.duration_minutes|interval=P1D)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.MEAN(visits.duration_minutes|interval=P1D))" , sum("STDDEV(visits.duration_minutes)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.STDDEV(visits.duration_minutes))" , sum("STDDEV(visits.duration_minutes|interval=P1D)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.STDDEV(visits.duration_minutes|interval=P1D))" , sum("SUM(visits.duration_minutes)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.SUM(visits.duration_minutes))" , sum("SUM(visits.duration_minutes|interval=P1D)" * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.SUM(visits.duration_minutes|interval=P1D))" , sum(age * exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row) / NULLIF(sum(exp(0.25 * (extract(epoch from registered_at) / 86400.0))) over (partition by patient_id order by registered_at rows between 6 preceding and current row), 0) as "EMA_7(patients.age)" , avg(risk_score) over (partition by patient_id order by effective_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(care_plans.risk_score)" , avg("COUNT(visits.visit_id)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.COUNT(visits.visit_id))" , avg("COUNT(visits.visit_id|interval=P1D)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.COUNT(visits.visit_id|interval=P1D))" , avg("COUNT(visits.visited_at)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.COUNT(visits.visited_at))" , avg("COUNT(visits.visited_at|interval=P1D)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.COUNT(visits.visited_at|interval=P1D))" , avg("MEAN(visits.duration_minutes)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.MEAN(visits.duration_minutes))" , avg("MEAN(visits.duration_minutes|interval=P1D)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.MEAN(visits.duration_minutes|interval=P1D))" , avg("STDDEV(visits.duration_minutes)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.STDDEV(visits.duration_minutes))" , avg("STDDEV(visits.duration_minutes|interval=P1D)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.STDDEV(visits.duration_minutes|interval=P1D))" , avg("SUM(visits.duration_minutes)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.SUM(visits.duration_minutes))" , avg("SUM(visits.duration_minutes|interval=P1D)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.SUM(visits.duration_minutes|interval=P1D))" , avg(age) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_LEVEL_7(patients.age)" , regr_slope(risk_score, effective_at) over (partition by patient_id order by effective_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(care_plans.risk_score)" , regr_slope("COUNT(visits.visit_id)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.COUNT(visits.visit_id))" , regr_slope("COUNT(visits.visit_id|interval=P1D)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.COUNT(visits.visit_id|interval=P1D))" , regr_slope("COUNT(visits.visited_at)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.COUNT(visits.visited_at))" , regr_slope("COUNT(visits.visited_at|interval=P1D)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.COUNT(visits.visited_at|interval=P1D))" , regr_slope("MEAN(visits.duration_minutes)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.MEAN(visits.duration_minutes))" , regr_slope("MEAN(visits.duration_minutes|interval=P1D)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.MEAN(visits.duration_minutes|interval=P1D))" , regr_slope("STDDEV(visits.duration_minutes)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.STDDEV(visits.duration_minutes))" , regr_slope("STDDEV(visits.duration_minutes|interval=P1D)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.STDDEV(visits.duration_minutes|interval=P1D))" , regr_slope("SUM(visits.duration_minutes)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.SUM(visits.duration_minutes))" , regr_slope("SUM(visits.duration_minutes|interval=P1D)", registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.SUM(visits.duration_minutes|interval=P1D))" , regr_slope(age, registered_at) over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "HOLT_WINTERS_TREND_7(patients.age)" , lag(risk_score, 1) over (partition by patient_id order by effective_at) as "LAG_1(care_plans.risk_score)" , lag("COUNT(visits.visit_id)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.COUNT(visits.visit_id))" , lag("COUNT(visits.visit_id|interval=P1D)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.COUNT(visits.visit_id|interval=P1D))" , lag("COUNT(visits.visited_at)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.COUNT(visits.visited_at))" , lag("COUNT(visits.visited_at|interval=P1D)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.COUNT(visits.visited_at|interval=P1D))" , lag("MEAN(visits.duration_minutes)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.MEAN(visits.duration_minutes))" , lag("MEAN(visits.duration_minutes|interval=P1D)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.MEAN(visits.duration_minutes|interval=P1D))" , lag("STDDEV(visits.duration_minutes)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.STDDEV(visits.duration_minutes))" , lag("STDDEV(visits.duration_minutes|interval=P1D)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.STDDEV(visits.duration_minutes|interval=P1D))" , lag("SUM(visits.duration_minutes)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.SUM(visits.duration_minutes))" , lag("SUM(visits.duration_minutes|interval=P1D)", 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.SUM(visits.duration_minutes|interval=P1D))" , lag(age, 1) over (partition by patient_id order by registered_at) as "LAG_1(patients.age)" , lag(risk_score, 3) over (partition by patient_id order by effective_at) as "LAG_3(care_plans.risk_score)" , lag("COUNT(visits.visit_id)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.COUNT(visits.visit_id))" , lag("COUNT(visits.visit_id|interval=P1D)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.COUNT(visits.visit_id|interval=P1D))" , lag("COUNT(visits.visited_at)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.COUNT(visits.visited_at))" , lag("COUNT(visits.visited_at|interval=P1D)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.COUNT(visits.visited_at|interval=P1D))" , lag("MEAN(visits.duration_minutes)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.MEAN(visits.duration_minutes))" , lag("MEAN(visits.duration_minutes|interval=P1D)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.MEAN(visits.duration_minutes|interval=P1D))" , lag("STDDEV(visits.duration_minutes)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.STDDEV(visits.duration_minutes))" , lag("STDDEV(visits.duration_minutes|interval=P1D)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.STDDEV(visits.duration_minutes|interval=P1D))" , lag("SUM(visits.duration_minutes)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.SUM(visits.duration_minutes))" , lag("SUM(visits.duration_minutes|interval=P1D)", 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.SUM(visits.duration_minutes|interval=P1D))" , lag(age, 3) over (partition by patient_id order by registered_at) as "LAG_3(patients.age)" , lag(risk_score, 7) over (partition by patient_id order by effective_at) as "LAG_7(care_plans.risk_score)" , lag("COUNT(visits.visit_id)", 7) over (partition by patient_id order by registered_at) as "LAG_7(patients.COUNT(visits.visit_id))" , lag("COUNT(visits.visit_id|interval=P1D)", 7) over (partition by patient_id order by registered_at) as "LAG_7(patients.COUNT(visits.visit_id|interval=P1D))" , lag("COUNT(visits.visited_at)", 7) over (partition by patient_id order by registered_at) as "LAG_7(patients.COUNT(visits.visited_at))" , lag("COUNT(visits.visited_at|interval=P1D)", 7) over (partition by patient_id order by registered_at) as "LAG_7(patients.COUNT(visits.visited_at|interval=P1D))" , lag("MEAN(visits.duration_minutes)", 7) over (partition by patient_id order by registered_at) as "LAG_7(patients.MEAN(visits.duration_minutes))" , lag("MEAN(visits.duration_minutes|interval=P1D)", 7) over (partition by patient_id order by registered_at) as "LAG_7(patients.MEAN(visits.duration_minutes|interval=P1D))" , lag("STDDEV(visits.duration_minutes)", 7) over (partition by patient_id order by 