        else ("COUNT(visits.visited_at|interval=P1D)" - lag("COUNT(visits.visited_at|interval=P1D)", 1) over (partition by patient_id order by registered_at)) / lag("COUNT(visits.visited_at|interval=P1D)", 1) over (partition by patient_id order by registered_at)
