        when lag("MEAN(visits.duration_minutes)", 1) over (partition by patient_id order by registered_at) is null or lag("MEAN(visits.duration_minutes)", 1) over (partition by patient_id order by registered_at) = 0 then null
        else ("MEAN(visits.duration_minutes)" - lag("MEAN(visits.duration_minutes)", 1) over (partition by patient_id order by registered_at)) / lag("MEAN(visits.duration_minutes)", 1) over (partition by patient_id order by registered_at)
