        else ("STDDEV(visits.duration_minutes|interval=P1D)" - lag("STDDEV(visits.duration_minutes|interval=P1D)", 1) over (partition by patient_id order by registered_at)) / lag("STDDEV(visits.duration_minutes|interval=P1D)", 1) over (partition by patient_id order by registered_at)
