        else ("SUM(visits.duration_minutes|interval=P1D)" - lag("SUM(visits.duration_minutes|interval=P1D)", 1) over (partition by patient_id order by registered_at)) / lag("SUM(visits.duration_minutes|interval=P1D)", 1) over (partition by patient_id order by registered_at)
