stered_at rows between 2 preceding and current row) as "ROLLING_MEAN_3(patients.MEAN(visits.duration_minutes))" , avg("MEAN(visits.duration_minutes|interval=P1D)") over (partition by patient_id order by registered_at rows between 2 preceding and current row) as "ROLLING_MEAN_3(patients.MEAN(visits.duration_minutes|interval=P1D))" , avg("STDDEV(visits.duration_minutes)") over (partition by patient_id order by registered_at rows between 2 preceding and current row) as "ROLLING_MEAN_3(patients.STDDEV(visits.duration_minutes))" , avg("STDDEV(visits.duration_minutes|interval=P1D)") over (partition by patient_id order by registered_at rows between 2 preceding and current row) as "ROLLING_MEAN_3(patients.STDDEV(visits.duration_minutes|interval=P1D))" , avg("SUM(visits.duration_minutes)") over (partition by patient_id order by registered_at rows between 2 preceding and current row) as "ROLLING_MEAN_3(patients.SUM(visits.duration_minutes))" , avg("SUM(visits.duration_minutes|interval=P1D)") over (partition by patient_id order by registered_at rows between 2 preceding and current row) as "ROLLING_MEAN_3(patients.SUM(visits.duration_minutes|interval=P1D))" , avg(age) over (partition by patient_id order by registered_at rows between 2 preceding and current row) as "ROLLING_MEAN_3(patients.age)" , percentile_cont(0.5) within group (order by risk_score) over (partition by patient_id order by effective_at rows between 6 preceding and current row) as "ROLLING_MEDIAN_7(care_plans.risk_score)" , percentile_cont(0.5) within group (order by "COUNT(visits.visit_id)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "ROLLING_MEDIAN_7(patients.COUNT(visits.visit_id))" , percentile_cont(0.5) within group (order by "COUNT(visits.visit_id|interval=P1D)") over (partition by patient_id order by registered_at rows between 6 preceding and current row) as "ROLLING_MEDIAN_7(patients.COUNT(visits.visit_id|interval=P1D))" , percentile_cont(0.5) within